if (! function_exists('multi_source_research')) {
    function multi_source_research($topic, $timeout = null, $max_github = null)
    {
        $topic = isset($topic) ? trim($topic) : '';
        if ($topic === '') {
            return ['error' => 'Topic is required.', 'sources' => []];
        }

        $timeout = isset($timeout) ? max(5, min(30, (int)$timeout)) : 15;
        $max_github = isset($max_github) ? max(1, min(10, (int)$max_github)) : 5;

        $results = [];
        $errors = [];

        // Helper: fetch a URL with timeout
        $fetch = function($url, $timeout_sec) {
            $ctx = stream_context_create([
                'http' => ['method' => 'GET', 'header' => 'User-Agent: self-bootstrapping-agent/1.0', 'timeout' => $timeout_sec, 'ignore_errors' => true],
                'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
            ]);
            $err = null;
            set_error_handler(function($s, $m) use (&$err) { $err = $m; return true; });
            $body = @file_get_contents($url, false, $ctx);
            $headers = $http_response_header ?? [];
            restore_error_handler();
            $status = 0;
            foreach ($headers as $i => $h) {
                if ($i === 0 && preg_match('#HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
            }
            return ['status' => $status, 'body' => $body, 'error' => $err];
        };

        // --- Source 1: Wikipedia ---
        $wiki_safe = str_replace(' ', '_', $topic);
        $wiki_url = 'https://en.wikipedia.org/w/api.php?action=query&titles=' . rawurlencode($wiki_safe) . '&prop=extracts&exintro=true&explaintext=true&format=json&redirects=1';
        $wiki_resp = $fetch($wiki_url, $timeout);

        $wiki = ['source' => 'Wikipedia', 'status' => 0, 'title' => null, 'extract' => null, 'error' => null];

        if ($wiki_resp['body'] === false) {
            $wiki['error'] = $wiki_resp['error'] ?? 'Failed to fetch Wikipedia';
        } else {
            $wiki['status'] = $wiki_resp['status'];
            $data = json_decode($wiki_resp['body'], true);
            if ($data && isset($data['query']['pages'])) {
                $pages = $data['query']['pages'];
                foreach ($pages as $id => $page) {
                    if ($id === '-1') {
                        $wiki['error'] = 'Page not found';
                    } else {
                        $wiki['title'] = $page['title'] ?? null;
                        $extract = $page['extract'] ?? '';
                        $wiki['extract'] = mb_strlen($extract) > 2000 ? mb_substr($extract, 0, 2000) . '...' : $extract;
                    }
                    break;
                }
            } else {
                $wiki['error'] = 'Failed to parse Wikipedia response';
            }
        }

        // --- Source 2: GitHub ---
        $github_url = 'https://api.github.com/search/repositories?q=' . rawurlencode($topic . '+language:php') . '&sort=stars&order=desc&per_page=' . $max_github;
        $gh_resp = $fetch($github_url, $timeout);

        $github = ['source' => 'GitHub', 'status' => 0, 'total_count' => 0, 'repos' => [], 'error' => null];

        if ($gh_resp['body'] === false) {
            $github['error'] = $gh_resp['error'] ?? 'Failed to fetch GitHub';
        } else {
            $github['status'] = $gh_resp['status'];
            $data = json_decode($gh_resp['body'], true);
            if ($data && isset($data['items'])) {
                $github['total_count'] = $data['total_count'] ?? 0;
                foreach ($data['items'] as $repo) {
                    $github['repos'][] = [
                        'name' => $repo['full_name'] ?? '',
                        'stars' => $repo['stargazers_count'] ?? 0,
                        'description' => $repo['description'] ?? '',
                        'url' => $repo['html_url'] ?? '',
                        'forks' => $repo['forks_count'] ?? 0,
                        'topics' => $repo['topics'] ?? [],
                    ];
                }
            } else {
                $github['error'] = 'Failed to parse GitHub response';
            }
        }

        // Extract rate limit info
        if (preg_match('/x-ratelimit-remaining:\s*(\d+)/i', implode("\n", $http_response_header ?? []), $m)) {
            $github['rate_limit_remaining'] = (int)$m[1];
        }

        // --- Source 3: Packagist (PHP package registry) ---
        $packagist_url = 'https://packagist.org/search.json?q=' . rawurlencode($topic) . '&per_page=5';
        $pkg_resp = $fetch($packagist_url, $timeout);

        $packagist = ['source' => 'Packagist', 'status' => 0, 'total' => 0, 'packages' => [], 'error' => null];

        if ($pkg_resp['body'] === false) {
            $packagist['error'] = $pkg_resp['error'] ?? 'Failed to fetch Packagist';
        } else {
            $packagist['status'] = $pkg_resp['status'];
            $data = json_decode($pkg_resp['body'], true);
            if ($data && isset($data['results'])) {
                $packagist['total'] = $data['total'] ?? count($data['results']);
                foreach ($data['results'] as $pkg) {
                    $packagist['packages'][] = [
                        'name' => $pkg['name'] ?? '',
                        'description' => $pkg['description'] ?? '',
                        'url' => $pkg['url'] ?? '',
                        'downloads' => $pkg['downloads'] ?? 0,
                        'favers' => $pkg['favers'] ?? 0,
                    ];
                }
            } else {
                $packagist['error'] = 'Failed to parse Packagist response';
            }
        }

        // --- Consolidated Summary ---
        $sources_ok = 0;
        if ($wiki['title'] !== null) $sources_ok++;
        if ($github['total_count'] > 0) $sources_ok++;
        if ($packagist['total'] > 0) $sources_ok++;

        $all_info = [];
        if ($wiki['title']) $all_info[] = 'Wikipedia: "' . $wiki['title'] . '"';
        if ($github['total_count'] > 0) $all_info[] = 'GitHub: ' . $github['total_count'] . ' repos found';
        if ($packagist['total'] > 0) $all_info[] = 'Packagist: ' . $packagist['total'] . ' packages found';

        $consolidated = 'Cross-referenced ' . $sources_ok . '/3 sources for "' . $topic . '". ' . implode(' | ', $all_info) . '.';

        return [
            'error' => null,
            'topic' => $topic,
            'consolidated' => $consolidated,
            'sources_queried' => 3,
            'sources_with_data' => $sources_ok,
            'sources' => [
                'wikipedia' => $wiki,
                'github' => $github,
                'packagist' => $packagist,
            ],
            'meta' => [
                'note' => 'Multi-source research pipeline: queries Wikipedia (encyclopedic), GitHub (code/projects), Packagist (PHP packages) for comprehensive topic coverage.',
            ],
        ];
    }
